#include<bits/stdc++.h>
using namespace std;
struct FHQ_Treap
{
    struct node
    {
        long long l,r;
        long long val,key;
        long long siz,max1;
        long long rev_tag,add_tag;
        node():max1(-1e12){}
    }t[100010];
    long long root,tot;
    long long newnode(long long v)
    {
        t[++tot].val=v;
        t[tot].key=rand();
        t[tot].siz=1;
        return tot;
    }
    void pushup(long long x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
        t[x].max1=max({t[t[x].l].max1,t[t[x].r].max1,t[x].val});
    }
    void pushdown(long long x)
    {
        if(t[x].rev_tag)
        {
            swap(t[x].l,t[x].r);
            t[t[x].l].rev_tag^=1;
            t[t[x].r].rev_tag^=1;
            t[x].rev_tag=0;
        }
        if(t[x].add_tag)
        {
            t[t[x].l].val+=t[x].add_tag;
            t[t[x].r].val+=t[x].add_tag;
            t[t[x].l].max1+=t[x].add_tag;
            t[t[x].r].max1+=t[x].add_tag;
            t[t[x].l].add_tag+=t[x].add_tag;
            t[t[x].r].add_tag+=t[x].add_tag;
            t[x].add_tag=0;
        }
    }
    void split(long long p,long long v,long long &x,long long &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        pushdown(p);
        if(t[t[p].l].siz+1<=v)
        {
            x=p;
            split(t[p].r,v-t[t[p].l].siz-1,t[p].r,y);
        }
        else
        {
            y=p;
            split(t[p].l,v,x,t[p].l);
        }
        pushup(p);
    }
    long long merge(long long x,long long y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        pushdown(x);
        pushdown(y);
        if(t[x].key<t[y].key)
        {
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    void insert(long long x)
    {
        root=merge(root,newnode(x));
    }
    void reverse(long long l,long long r)
    {
        long long x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        t[y].rev_tag^=1;
        root=merge(merge(x,y),z);
    }
    void add(long long l,long long r,long long v)
    {
        long long x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        t[y].add_tag+=v;
        t[y].max1+=v;
        t[y].val+=v;
        root=merge(merge(x,y),z);
    }
    long long getmax(long long l,long long r)
    {
        long long x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        long long ans=t[y].max1;
        root=merge(merge(x,y),z);
        return ans;
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        t.insert(0);
    }
    while(m--)
    {
        long long op,l,r,v;
        scanf("%lld%lld%lld",&op,&l,&r);
        if(op==1)
        {
            scanf("%lld",&v);
            t.add(l,r,v);
        }
        else if(op==2)
        {
            t.reverse(l,r);
        }
        else
        {
            printf("%lld\n",t.getmax(l,r));
        }
    }
    return 0;
}
